## components/MultiImageUploader.tsx

```tsx
import React, { useRef, useState, useEffect } from 'react';
import Icon from './Icons';

interface MultiImageUploaderProps {
  onFilesChange: (files: { file: File; previewUrl: string }[]) => void;
  uploadedFiles: { file: File; previewUrl: string }[];
  label: string;
  maxFiles?: number;
}

const MultiImageUploader: React.FC<MultiImageUploaderProps> = ({ 
  onFilesChange, 
  uploadedFiles, 
  label, 
  maxFiles = 3 
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  useEffect(() => {
    // Cleanup old URLs when uploadedFiles change or component unmounts
    return () => {
      uploadedFiles.forEach(f => URL.revokeObjectURL(f.previewUrl));
    };
  }, [uploadedFiles]);

  const handleNewFiles = (newlySelectedFiles: File[]) => {
    if (newlySelectedFiles.length === 0) return;

    const currentFileCount = uploadedFiles.length;
    const filesToProcess = newlySelectedFiles.slice(0, maxFiles - currentFileCount);

    const newFilesData = filesToProcess.map(file => ({
      file,
      previewUrl: URL.createObjectURL(file),
    }));

    onFilesChange([...uploadedFiles, ...newFilesData]);
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(event.target.files || []);
    handleNewFiles(files);

    // Reset input value so the same file can be selected again if needed
    if (event.target) {
      event.target.value = '';
    }
  };

  const handleRemoveFile = (indexToRemove: number) => {
    const newFiles = uploadedFiles.filter((_, index) => index !== indexToRemove);
    if (uploadedFiles[indexToRemove]) {
      URL.revokeObjectURL(uploadedFiles[indexToRemove].previewUrl);
    }
    onFilesChange(newFiles);
  };

  const handleDragOver = (event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    setIsDragging(false);

    const droppedFiles = Array.from(event.dataTransfer.files).filter(file => file.type.startsWith('image/'));
    handleNewFiles(droppedFiles);
  };

  const handleClick = () => {
    if (uploadedFiles.length < maxFiles) {
        fileInputRef.current?.click();
    }
  };

  const canAddMoreFiles = uploadedFiles.length < maxFiles;

  return (
    <div>
        <label className="block text-xs font-bold text-gray-400 uppercase tracking-wide mb-2 flex items-center gap-2">
          <Icon name="multi_upload" className="w-4 h-4" />
          {label} ({uploadedFiles.length} / {maxFiles})
        </label>
        <input 
          type="file" 
          ref={fileInputRef}
          className="hidden" 
          accept="image/png, image/jpeg, image/jpg"
          onChange={handleFileChange}
          multiple // Allow multiple file selection
        />

        {/* Dropzone / Add more files area */}
        {canAddMoreFiles ? (
            <div
                onClick={handleClick}
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
                onDrop={handleDrop}
                className={`w-full h-32 border border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all duration-300
                    ${isDragging
                        ? 'border-green-500 bg-green-500/10 shadow-[0_0_15px_rgba(16,185,129,0.2)]' 
                        : 'border-gray-700 bg-gray-900/30 hover:border-gray-500 hover:bg-gray-800/50'}
                `}
            >
                <div className="mb-3 text-gray-500 group-hover:text-green-400 transition-colors">
                    <Icon name="upload" className="w-8 h-8" />
                </div>
                <p className="text-gray-400 text-center text-sm px-4 font-medium">Klik atau Seret {uploadedFiles.length === 0 ? 'Foto Produk' : `Foto Tambahan (hingga ${maxFiles - uploadedFiles.length})`}</p>
                <p className="text-[10px] text-gray-500 mt-1 uppercase tracking-wider">PNG, JPG, JPEG</p>
            </div>
        ) : (
            <div className="w-full h-16 border border-gray-700 rounded-xl flex items-center justify-center bg-gray-900/50 text-gray-500 text-sm font-medium">
                Maksimal {maxFiles} foto telah diunggah.
            </div>
        )}

        {/* Uploaded Files Preview */}
        {uploadedFiles.length > 0 && (
            <div className="mt-4 grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-6 gap-3">
                {uploadedFiles.map((fileData, index) => (
                    <div key={index} className="relative w-full aspect-square bg-gray-800 rounded-lg overflow-hidden group">
                        <img src={fileData.previewUrl} alt={`Preview ${index + 1}`} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                            <button
                                onClick={() => handleRemoveFile(index)}
                                className="bg-red-500 text-white rounded-full h-8 w-8 flex items-center justify-center hover:bg-red-600 transition shadow-lg transform hover:scale-110"
                                aria-label={`Remove image ${index + 1}`}
                            >
                                <Icon name="close" className="w-4 h-4" />
                            </button>
                        </div>
                        <span className="absolute bottom-1 right-1 bg-black/70 text-white text-[9px] px-1.5 py-0.5 rounded-full z-10">
                            Foto {index + 1}
                        </span>
                    </div>
                ))}
            </div>
        )}
    </div>
  );
};

export default MultiImageUploader;
```

