import React, { useState, useEffect } from 'react';
import { generateImages, editImage, generateConceptualImages } from '../services/geminiService';
import { ImageAspectRatio, Generation } from '../types';
import { IMAGE_ASPECT_RATIOS, IMAGE_TEMPLATES, IMAGE_STYLES, IMAGE_LIGHTING, GENERATION_MODES } from '../constants';
import LoadingSpinner from './LoadingSpinner';
import MultiImageUploader from './MultiImageUploader'; // Import the new component
import { fileToBase64 } from '../utils/fileUtils';
import Icon from './Icons';

interface ImageGeneratorProps {
  addGenerationToHistory: (generation: Generation) => void;
}

const IMAGE_PROMPT_TIPS = [
  "Spesifik: 'Danau pegunungan yang tenang saat matahari terbit dengan pantulan' lebih baik daripada 'Danau yang bagus'.",
  "Sertakan kata sifat: Jelaskan warna, suasana, gaya (mis., 'cerah', 'dramatis', 'minimalis').",
  "Tentukan gaya artistik: Gunakan istilah seperti 'lukisan digital', 'fotorealistik', 'cat air', 'cyberpunk'.",
  "Definisikan pencahayaan: 'Golden hour', 'cahaya neon', 'pencahayaan studio', 'siluet dramatis'.",
  "Tambahkan detail: Sebutkan tekstur, bahan, lingkungan, waktu, cuaca.",
  "Pertimbangkan komposisi: 'Close-up shot', 'wide-angle', 'dari atas', 'sudut dinamis'.",
  "Untuk pengeditan/multi-gambar: Jelaskan dengan jelas bagaimana semua gambar harus berinteraksi atau digabungkan, dan efek yang diinginkan pada output 6 konsep.",
  "Eksperimen: Cobalah menggabungkan elemen atau konsep yang tidak biasa."
];

const ImageGenerator: React.FC<ImageGeneratorProps> = ({ addGenerationToHistory }) => {
  const [prompt, setPrompt] = useState<string>('');
  const [aspectRatio, setAspectRatio] = useState<ImageAspectRatio>('1:1');
  const [style, setStyle] = useState<string>('');
  const [lighting, setLighting] = useState<string>('');
  const [enhanceFace, setEnhanceFace] = useState<boolean>(false);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);
  const [selectedModeId, setSelectedModeId] = useState<string | null>(null);

  // State for multiple images
  const [uploadedFiles, setUploadedFiles] = useState<{ file: File; previewUrl: string }[]>([]);

  const [showPromptTips, setShowPromptTips] = useState<boolean>(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  useEffect(() => {
    // Clean up object URLs when component unmounts or uploadedFiles change
    return () => {
      uploadedFiles.forEach(fileData => URL.revokeObjectURL(fileData.previewUrl));
    };
  }, [uploadedFiles]);

  const handleUploadedFilesChange = (files: { file: File; previewUrl: string }[]) => {
    // Revoke URLs for files that are no longer present
    const oldFiles = uploadedFiles.filter(oldFile => !files.some(newFile => newFile.file === oldFile.file));
    oldFiles.forEach(fileData => URL.revokeObjectURL(fileData.previewUrl));

    setUploadedFiles(files);
    setGeneratedImages([]); // Clear generated images when input changes
    setError(null);
    setStyle(''); // Clear style when uploading to allow AI inference
  };

  const handleModeSelect = (modeId: string) => {
      const selectedMode = GENERATION_MODES.find(m => m.id === modeId);
      if (selectedMode) {
          setPrompt(selectedMode.prompt);
          setAspectRatio(selectedMode.aspectRatio);
          setSelectedModeId(modeId);
          setStyle(''); // Clear style on mode select to prevent conflicts
      }
  };

  const handleGenerate = async () => {
    const trimmedPrompt = prompt.trim();
    if (!trimmedPrompt) {
      setError('Silakan masukkan prompt.');
      return;
    }
    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);
    const generationId = crypto.randomUUID();

    const numUploadedImages = uploadedFiles.length;
    const uploadedFileNames = uploadedFiles.map(img => img.file.name);

    try {
      // Construct final prompt with advanced details
      let finalPrompt = trimmedPrompt;
      const advancedDetails = [];

      // Only add style if not in image upload/edit/conceptual mode (AI infers style then)
      if (numUploadedImages < 2 && style) advancedDetails.push(style); // Style is inferred for 2+ images

      if (lighting) advancedDetails.push(`${lighting} lighting`);
      if (enhanceFace) advancedDetails.push("enhance face details, clear face, detailed eyes");

      if (advancedDetails.length > 0) {
          finalPrompt = `${finalPrompt}, ${advancedDetails.join(', ')}`;
      }

      if (numUploadedImages >= 2) {
        // Multi-image Conceptual Generation (2 or 3 images)
        const imagesPayload: { data: string; mimeType: string }[] = await Promise.all(
          uploadedFiles.map(async fileData => ({
            data: await fileToBase64(fileData.file),
            mimeType: fileData.file.type
          }))
        );

        const images = await generateConceptualImages(
            finalPrompt,
            imagesPayload, // Pass all uploaded images
            aspectRatio
        );
        setGeneratedImages(images);
        addGenerationToHistory({
            id: generationId,
            prompt: trimmedPrompt,
            timestamp: Date.now(),
            type: 'image',
            status: 'completed',
            outputs: images,
            config: {
                uploadedImages: uploadedFileNames,
                aspectRatio,
                lighting,
                enhanceFace,
                mode: 'conceptual-multi-image',
                numberOfConcepts: images.length,
            },
        });

      } else if (numUploadedImages === 1) {
        // Single image editing mode
        const imagesPayload = [{ 
            data: await fileToBase64(uploadedFiles[0].file), 
            mimeType: uploadedFiles[0].file.type 
        }];

        const generationConfig = { uploadedImages: uploadedFileNames, aspectRatio, lighting, enhanceFace, mode: 'single-image-edit' };
        const images = await editImage(finalPrompt, imagesPayload, aspectRatio);
        setGeneratedImages(images);
        addGenerationToHistory({
          id: generationId,
          prompt: trimmedPrompt,
          timestamp: Date.now(),
          type: 'image',
          status: 'completed',
          outputs: images,
          config: generationConfig,
        });
      } else {
        // Text-to-image mode (numberOfImages is hardcoded to 1 in service)
        const generationConfig = { aspectRatio, style, lighting, enhanceFace, mode: 'text-to-image' };
        const images = await generateImages(finalPrompt, aspectRatio);
        setGeneratedImages(images);
        addGenerationToHistory({
          id: generationId,
          prompt: trimmedPrompt,
          timestamp: Date.now(),
          type: 'image',
          status: 'completed',
          outputs: images,
          config: generationConfig,
        });
      }
    } catch (e: any) {
      const errorMessage = `Terjadi kesalahan: ${e.message}`;
      setError(errorMessage);
       const config = numUploadedImages >= 2
            ? { uploadedImages: uploadedFileNames, aspectRatio, lighting, enhanceFace, mode: 'conceptual-multi-image' }
            : numUploadedImages === 1
            ? { uploadedImages: uploadedFileNames, aspectRatio, lighting, enhanceFace, mode: 'single-image-edit' }
            : { aspectRatio, style, lighting, enhanceFace, mode: 'text-to-image' };
      addGenerationToHistory({
        id: generationId,
        prompt: trimmedPrompt,
        timestamp: Date.now(),
        type: 'image',
        status: 'failed',
        outputs: [],
        config,
        error: errorMessage,
      });
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (event: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (event.ctrlKey && event.key === 'Enter') {
      event.preventDefault(); // Prevent new line in textarea
      handleGenerate();
    }
  };

  const handleCopyJSON = (src: string, index: number) => {
    const dataToCopy = {
        prompt: prompt,
        config: {
            aspectRatio,
            style: isMultiImageMode ? 'AI inferred' : style,
            lighting,
            enhanceFace,
            mode: isMultiImageMode ? 'conceptual-multi-image' : isSingleImageEditMode ? 'single-image-edit' : 'text-to-image'
        },
        image: src 
    };

    navigator.clipboard.writeText(JSON.stringify(dataToCopy, null, 2))
        .then(() => {
            setCopiedIndex(index);
            setTimeout(() => setCopiedIndex(null), 2000);
        })
        .catch(err => console.error('Gagal menyalin JSON:', err));
  };

  const numUploadedImages = uploadedFiles.length;
  const isMultiImageMode = numUploadedImages >= 2;
  const isSingleImageEditMode = numUploadedImages === 1;

  const getGenerateButtonText = () => {
    if (isMultiImageMode) return 'Buat 6 Konsep';
    if (isSingleImageEditMode) return 'Magic Edit';
    return 'Buat Gambar';
  };

  const getPromptLabel = () => {
      if (isMultiImageMode) return `Instruksi Konsep (${numUploadedImages} Foto)`;
      if (isSingleImageEditMode) return `Instruksi Edit (${numUploadedImages} Foto)`;
      return "Prompt Kreatif";
  };

  const getPromptPlaceholder = () => {
    if (numUploadedImages >= 2) {
      return "cth., Gabungkan produk ini dengan model ini, hasilkan 6 konsep iklan unik, di latar belakang minimalis mewah...";
    }
    if (numUploadedImages === 1) {
      return "cth., Ubah latar belakang foto ini menjadi pantai tropis, atau tambahkan detail rambut...";
    }
    return "cth., Seekor singa agung memakai mahkota, pencahayaan sinematik, detail bulu...";
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
      {/* LEFT COLUMN: Inputs */}
      <div className="flex flex-col gap-8">
        {/* Template Section */}
        <div>
          <div className="flex items-center justify-between mb-4">
             <h3 className="text-xs font-bold uppercase tracking-wider text-gray-400 flex items-center gap-2">
               <Icon name="magic" className="w-4 h-4" />
               Template Inspirasi
             </h3>
          </div>
          <div className="flex flex-wrap gap-2">
              {IMAGE_TEMPLATES.map(template => (
                  <button
                      key={template.name}
                      onClick={() => setPrompt(template.prompt)}
                      className="group bg-gray-800 hover:bg-gray-700 border border-gray-700 hover:border-gray-500 text-gray-400 hover:text-white text-xs font-medium py-2 px-3 rounded-lg transition-all duration-300 flex items-center gap-2"
                  >
                      <Icon name={template.icon} className="w-4 h-4 opacity-70 group-hover:opacity-100" />
                      <span>{template.name}</span>
                  </button>
              ))}
          </div>
        </div>

        {/* Utility Mode Selector Grid */}
        <div className="bg-gray-900/50 border border-gray-800 rounded-xl p-4">
             <label className="block text-xs font-bold text-green-400 uppercase tracking-wide mb-3 flex items-center gap-2">
                <Icon name="target" className="w-4 h-4" />
                Mode Kebutuhan (Otomatis)
             </label>
             <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                 {GENERATION_MODES.map(mode => (
                     <button
                        key={mode.id}
                        onClick={() => handleModeSelect(mode.id)}
                        className={`flex items-center gap-2 p-3 rounded-lg border text-left transition-all duration-200 ${
                            selectedModeId === mode.id 
                            ? 'bg-green-500/10 border-green-500/50 text-green-400 shadow-sm' 
                            : 'bg-gray-800 border-gray-700 text-gray-300 hover:border-gray-500 hover:bg-gray-750'
                        }`}
                     >
                         <div className={`p-1.5 rounded-md flex-shrink-0 ${selectedModeId === mode.id ? 'bg-green-500/20 text-green-400' : 'bg-gray-700 text-gray-400'}`}>
                            <Icon name={mode.icon} className="w-4 h-4" />
                         </div>
                         <span className="text-xs font-bold">{mode.label}</span>
                     </button>
                 ))}
             </div>
        </div>

        <div className="flex flex-col gap-6">
          {/* Multi Image Uploader */}
          <div className="grid grid-cols-1 gap-5">
             <MultiImageUploader 
                onFilesChange={handleUploadedFilesChange}
                uploadedFiles={uploadedFiles}
                label="Foto Produk"
                maxFiles={3}
             />
          </div>

          <div className="grid grid-cols-1 gap-5">
            <div className="w-full">
              <label htmlFor="prompt" className="block text-sm font-bold text-gray-300 mb-2">
                {getPromptLabel()}
              </label>
              <div className="relative group">
                <textarea
                  id="prompt"
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  onKeyDown={handleKeyDown}
                  className="w-full bg-gray-800 border border-gray-700 rounded-xl p-4 text-gray-100 placeholder-gray-500 focus:ring-1 focus:ring-green-500 focus:border-green-500 outline-none transition-all resize-none font-sans group-hover:border-gray-600"
                  rows={numUploadedImages >= 2 ? 5 : 4} // More rows for multi uploads
                  placeholder={getPromptPlaceholder()}
                />
                <div className="absolute bottom-3 right-3 text-xs text-gray-500 bg-gray-900/80 px-2 py-1 rounded border border-gray-700">Ctrl+Enter</div>
              </div>

               <div className="mt-2 flex justify-end">
                  <button
                      onClick={() => setShowPromptTips(!showPromptTips)}
                      className="text-gray-400 hover:text-green-400 text-xs font-medium flex items-center gap-1 transition"
                  >
                      {showPromptTips ? 'Sembunyikan Tips' : 'Lihat Tips Prompt'}
                      <Icon name="info" className="w-3 h-3" />
                  </button>
              </div>
              {showPromptTips && (
                  <div className="mt-2 p-4 bg-gray-800/50 border border-gray-700 rounded-lg text-gray-300 text-sm animate-fade-in">
                      <h4 className="font-bold mb-2 text-white flex items-center gap-2">
                        <Icon name="magic" className="w-4 h-4 text-green-400" />
                        Tips Prompt Pro
                      </h4>
                      <ul className="list-disc list-inside space-y-1 text-xs text-gray-400 ml-1">
                          {IMAGE_PROMPT_TIPS.map((tip, index) => (
                              <li key={index}>{tip}</li>
                          ))}
                      </ul>
                  </div>
              )}
            </div>

            {/* CONFIGURATION OPTIONS */}
            <div className="bg-gray-900/30 rounded-xl p-5 border border-gray-800 space-y-5">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                {/* Removed "Jumlah Gambar" Input */}
                <div>
                    <label htmlFor="aspect-ratio" className="block text-xs font-bold text-gray-400 uppercase tracking-wide mb-2">
                    Rasio Aspek
                    </label>
                    <select
                    id="aspect-ratio"
                    value={aspectRatio}
                    onChange={(e) => setAspectRatio(e.target.value as ImageAspectRatio)}
                        className="w-full bg-gray-800 border border-gray-700 rounded-lg p-2.5 text-gray-200 focus:ring-1 focus:ring-green-500 focus:border-green-500 outline-none hover:border-gray-600 transition"
                    >
                    {IMAGE_ASPECT_RATIOS.map((ratio) => (
                        <option key={ratio} value={ratio}>{ratio}</option>
                    ))}
                    </select>
                </div>
                </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                <div>
                    <label htmlFor="style" className="block text-xs font-bold text-gray-400 uppercase tracking-wide mb-2">
                        Gaya {isMultiImageMode && <span className='text-xs text-gray-600 normal-case'>(AI inferensi)</span>}
                    </label>
                    <select 
                        id="style" 
                        value={style} 
                        onChange={(e) => setStyle(e.target.value)} 
                        disabled={isMultiImageMode} // Disable when 2 or more images are uploaded
                        className={`w-full bg-gray-800 border border-gray-700 rounded-lg p-2.5 text-gray-200 focus:ring-1 focus:ring-green-500 focus:border-green-500 outline-none hover:border-gray-600 transition ${isMultiImageMode ? 'opacity-50 cursor-not-allowed' : ''}`}
                    >
                        <option value="">-- Default --</option>
                        {IMAGE_STYLES.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
                    <div>
                    <label htmlFor="lighting" className="block text-xs font-bold text-gray-400 uppercase tracking-wide mb-2">Pencahayaan</label>
                    <select id="lighting" value={lighting} onChange={(e) => setLighting(e.target.value)} className="w-full bg-gray-800 border border-gray-700 rounded-lg p-2.5 text-gray-200 focus:ring-1 focus:ring-green-500 focus:border-green-500 outline-none hover:border-gray-600 transition">
                        <option value="">-- Default --</option>
                        {IMAGE_LIGHTING.map(l => <option key={l} value={l}>{l}</option>)}
                    </select>
                </div>
            </div>

            <div className="flex items-center pt-2">
                <label className="relative inline-flex items-center cursor-pointer">
                    <input type="checkbox" id="enhance-face" checked={enhanceFace} onChange={(e) => setEnhanceFace(e.target.checked)} className="sr-only peer" />
                    <div className="w-11 h-6 bg-gray-700 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-green-600"></div>
                    <span className="ml-3 text-sm font-medium text-gray-300">Mode Perjelas Wajah</span>
                </label>
            </div>
            </div>

            <div className="mt-4">
                <button
                    onClick={handleGenerate}
                    disabled={isLoading}
